Primary city: {{$json.city_region}}
Target services: {{$json.keywords && $json.keywords.secondary ? $json.keywords.secondary : []}}
Target service areas: {{$json.business_entity && $json.business_entity.service_areas ? $json.business_entity.service_areas : []}}

