parameters.jsCode:
// Store research document globally for this execution
const raw = $json || {};

function pickRaw(input) {
  if (typeof input === "string") return input;
  if (!input || typeof input !== "object") return "";
  if (typeof input.text === "string") return input.text;
  if (typeof input.response === "string") return input.response;
  if (typeof input.output === "string") return input.output;
  if (typeof input.content === "string") return input.content;
  if (input.message && typeof input.message === "object") {
    if (typeof input.message.content === "string") return input.message.content;
  }
  return "";
}

let research = {};
try {
  const rawText = pickRaw(raw) || JSON.stringify(raw);
  const parsed = JSON.parse(rawText);
  if (parsed && typeof parsed === "object") {
    research = parsed;
  }
} catch (e) {
  research = {};
}

const workflowData = $getWorkflowStaticData('global');
workflowData.research_document = research;

const payload = $node["Webhook"].json.body ?? $node["Webhook"].json;
const out = {
  ...payload,
  research_document: research
};

function buildProgressUrl(payload) {
  const callbackUrl = payload.callback_url || (payload.body ? payload.body.callback_url : "");
  if (!callbackUrl) return "";
  return callbackUrl.replace('/orchestrator', '/progress');
}

function sendProgress(payload, percent, step, message) {
  const progressUrl = buildProgressUrl(payload);
  const jobId = payload.job_id || (payload.body ? payload.body.job_id : null);
  if (!progressUrl || !jobId) {
    return Promise.resolve();
  }
  return this.helpers.httpRequest({
    method: 'POST',
    url: progressUrl,
    json: true,
    body: {
      job_id: jobId,
      status: 'running',
      percent,
      step: step || '',
      message: message || ''
    }
  }).then(() => null).catch(() => null);
}

return sendProgress(out, 25, 'Research ready', 'Research generated').then(() => [{ json: out }]);

// Use provided research document from payload
const payload = $json.body ?? $json;
const provided = payload.research_document || (payload.body ? payload.body.research_document : {}) || {};
const research = (provided && typeof provided === "object") ? provided : {};

const workflowData = $getWorkflowStaticData('global');
workflowData.research_document = research;

const out = {
  ...payload,
  research_document: research
};

function buildProgressUrl(payload) {
  const callbackUrl = payload.callback_url || (payload.body ? payload.body.callback_url : "");
  if (!callbackUrl) return "";
  return callbackUrl.replace('/orchestrator', '/progress');
}

function sendProgress(payload, percent, step, message) {
  const progressUrl = buildProgressUrl(payload);
  const jobId = payload.job_id || (payload.body ? payload.body.job_id : null);
  const requestId = payload.request_id || payload.body?.request_id || "";
  const runPhase = payload.run_phase || payload.body?.run_phase || "initial";
  if (!progressUrl || !jobId || !requestId) {
    return Promise.resolve();
  }
  return this.helpers.httpRequest({
    method: 'POST',
    url: progressUrl,
    json: true,
    body: {
      job_id: jobId,
      request_id: requestId,
      status: 'running',
      percent,
      step: step || '',
      message: message || '',
      run_phase: runPhase
    }
  }).then(() => null).catch(() => null);
}

return sendProgress(out, 20, 'Research ready', 'Research provided').then(() => [{ json: out }]);

const webhook = $json || {};
const defaultCallbackUrl = "http://localhost:10008/wp-json/leadsforward/v1/orchestrator";
const callbackUrl = webhook.callback_url || webhook.body?.callback_url || defaultCallbackUrl;
const callbackAuthHeader = webhook.headers?.authorization || webhook.headers?.Authorization || "";

return [{
  json: {
    ok: true,
    request_id: "callback-test",
    updates: [],
    callback_url: callbackUrl,
    callback_auth_header: callbackAuthHeader,
    callback_payload: {
      payload: JSON.stringify({
        ok: true,
        request_id: "callback-test",
        updates: [],
        callback_url: callbackUrl
      })
    }
  }
}];

