const qualityWarnings = Array.isArray($json?.quality_warnings) ? [...$json.quality_warnings] : [];
const strictMediaAnnotations = webhookPayload.media_annotation_mode === 'strict' || webhookPayload.media_annotation_required === true;
const minExpected = Math.max(0, Number(webhookPayload.media_annotation_min_expected || 0));
if (strictMediaAnnotations && minExpected > 0 && mediaAnnotations.length < minExpected) {
  qualityWarnings.push(`Missing media_annotations (expected>=${minExpected}, got=${mediaAnnotations.length}, candidates=${candidateRows.length}). Continuing in fallback mode.`);
}
if (candidateRows.length > 0 && mediaAnnotations.length === 0) {
  qualityWarnings.push('No media_annotations present; callback will use theme fallback metadata only.');
}

function remapLegacyHomepageFieldKey(key) {
  if (typeof key !== 'string' || key.indexOf('.') === -1) return key;
  const [section, field] = key.split('.', 2);
  const sectionMap = {
    intro: 'service_intro',
    services: 'service_details',
    about: 'benefits',
    testimonials: 'trust_reviews'
  };
  const fieldMap = {
    hero_cta_primary: 'cta_primary_override',
    hero_cta_secondary: 'cta_secondary_override',
    cta_primary: 'cta_primary_override',
    cta_secondary: 'cta_secondary_override'
  };
  const mappedSection = sectionMap[section] || section;
  const mappedField = fieldMap[field] || field;
  return `${mappedSection}.${mappedField}`;
}

let remapCount = 0;
const normalizedUpdates = Array.isArray($json?.updates)
  ? $json.updates.map((update) => {
      if (!update || typeof update !== 'object') return update;
      const target = String(update.target || '');
      const id = String(update.id || '');
      if (target !== 'options' || id !== 'homepage' || !update.fields || typeof update.fields !== 'object') {
        return update;
      }
      const nextFields = {};
      for (const rawKey of Object.keys(update.fields)) {
        const mappedKey = remapLegacyHomepageFieldKey(rawKey);
        if (mappedKey !== rawKey) remapCount += 1;
        nextFields[mappedKey] = update.fields[rawKey];
      }
      return { ...update, fields: nextFields };
    })
  : $json?.updates;

if (remapCount > 0) {
  qualityWarnings.push(`Normalized ${remapCount} legacy homepage field keys before callback.`);
}

