  .map(item => item?.json || {})
  .filter(j => j && j.ok === false);

const items = allItems.filter(item => item?.json?.ok !== false);
if (!items.length) {
  const warnings = upstreamFailures.map(f => {
    const pageType = f.page_type || 'unknown';
    const err = String(f.error || 'unknown_error');
    const detail = String(f.details || '').trim();
    return detail
