      warnings.push(`Scope mismatch: core_pages enabled but missing page_type=${type}`);
    }
  }
}
if (scope.blog_posts) {
  const blogCount = pageTypeCounts.post || 0;
  if (blogCount < 5) {
    warnings.push(`Scope mismatch: blog_posts enabled but only ${blogCount} blog blueprints were produced (expected at least 5).`);
  }
}

for (const item of items) {
  if (!item.json || typeof item.json !== 'object') item.json = {};
  const existing = Array.isArray(item.json.quality_warnings) ? item.json.quality_warnings : [];
  item.json.quality_warnings = Array.from(new Set(existing.concat(warnings)));
  item.json.page_type_counts = pageTypeCounts;
  item.json.scope_mismatch = warnings.some(w => String(w).startsWith('Scope mismatch:'));
  item.json.parse_failed_count = upstreamFailures.length;
}

return items;

// Cache blueprint input for retries
const data = $getWorkflowStaticData('global');
if (!data.blueprint_cache || typeof data.blueprint_cache !== 'object') data.blueprint_cache = {};
const key = `${$json.request_id || ''}:${$json.blueprint_index ?? ''}`;
if (key) data.blueprint_cache[key] = $json;
return [{ json: $json }];

// Decide which pages need an LLM retry
const items = $input.all();

function isSevere(w) {
  return /duplicate|repeated|generic|in your area|city repeated|is not registered|is not allowed/i.test(String(w || ""));
}

return items.map(item => {
  const j = item.json || {};
  const warnings = Array.isArray(j.quality_warnings) ? j.quality_warnings : [];
  const retry_count = typeof j.retry_count === "number" ? j.retry_count : 0;
  const needs_retry = (j.ok === false || warnings.some(isSevere)) && retry_count < 2;

  return {
    json: {
      ...j,
      needs_retry,
      retry_count,
      retry_instructions: warnings.join(" | "),
    },
  };
});

// Build retry input from cached blueprint
const data = $getWorkflowStaticData('global') || {};
const cache = data.blueprint_cache || {};
const requestId = $json.request_id || '';
const index = ($json.blueprint_index ?? '');
const key = `${requestId}:${index}`;
const base = cache[key] || {};
const retry_count = (base.retry_count ?? 0) + 1;
return [{
  json: {
    ...base,
    retry_instructions: $json.retry_instructions || 'Fix quality warnings and ensure uniqueness',
    retry_count
  }
}];

