parameters.jsCode:
function pickRaw(input) {
  if (typeof input === "string") return input;
  if (typeof input?.text === "string") return input.text;
  if (typeof input?.output === "string") return input.output;
  if (typeof input?.response === "string") return input.response;
  if (typeof input?.data?.text === "string") return input.data.text;
  if (typeof input?.message?.content === "string") return input.message.content;
  return input;
}

function deepClean(value) {
  if (typeof value === "string") {
    return value.split(String.fromCharCode(13)).join(String.fromCharCode(10));
  }
  if (Array.isArray(value)) return value.map(deepClean);
  if (value && typeof value === "object") {
    const cleaned = {};
    for (const key in value) cleaned[key] = deepClean(value[key]);
    return cleaned;
  }
  return value;
}

function stripHtml(value) {
  return String(value || "")
    .replace(/<[^>]*>/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function trimToWords(value, maxWords) {
  const text = stripHtml(value);
  if (!text) return "";
  const words = text.split(/\s+/);
  if (words.length <= maxWords) return words.join(" ");
  return words.slice(0, maxWords).join(" ");
}

function findPostMetaId(updates) {
  const hit = updates.find(u => u?.target === "post_meta" && u?.id);
  return hit?.id || null;
}

function pickShortDesc(updates) {
  const suffixes = [
    ".hero_subheadline",
    ".hero_supporting_text",
    ".section_intro",
    ".section_body",
    ".section_body_secondary",
  ];
  for (const update of updates) {
    const fields = update?.fields;
    if (!fields || typeof fields !== "object") continue;
    const keys = Object.keys(fields);
    for (const suffix of suffixes) {
      const key = keys.find(k => k.toLowerCase().endsWith(suffix));
      if (!key) continue;
      const value = trimToWords(fields[key], 28);
      if (value) return value;
    }
  }
  return "";
}

function parseJsonSafely(raw) {
  if (typeof raw !== "string") return { ok: true, value: raw };

  const candidates = [];
  const trimmed = raw.trim();
  candidates.push(trimmed);

  const fence = trimmed.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (fence && fence[1]) candidates.push(fence[1].trim());

  const firstBrace = trimmed.indexOf("{");
  const lastBrace = trimmed.lastIndexOf("}");
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    candidates.push(trimmed.slice(firstBrace, lastBrace + 1));
  }

  const repaired = trimmed.replace(/,\s*}/g, "}").replace(/,\s*]/g, "]");
  candidates.push(repaired);

  let lastError = null;
  for (const candidate of candidates) {
    try {
      return { ok: true, value: JSON.parse(candidate) };
    } catch (e) {
      lastError = e;
    }
  }

  return { ok: false, error: String(lastError?.message || "Unable to parse JSON") };
}

function parseOne(itemJson) {
  const inputCtx = itemJson && typeof itemJson === "object" ? itemJson : {};
  const requestIdHint = inputCtx.request_id || null;
  const pageTypeHint = inputCtx.page_type || null;
  const primaryHint = inputCtx.primary_keyword || "";
  const secondaryHint = Array.isArray(inputCtx.secondary_keywords) ? inputCtx.secondary_keywords : [];
  const businessHint = inputCtx.business_name || "";
  const cityHint = inputCtx.city_region || "";
  const styleHint = inputCtx.style_profile?.id || inputCtx.style_profile_id || "";

  const raw = pickRaw(inputCtx);
  const parsedResult = parseJsonSafely(raw);
  if (!parsedResult.ok) {
    return {
      json: {
        ok: false,
        status: 500,
        error: "Invalid JSON from LLM",
        details: parsedResult.error,
        page_type: pageTypeHint,
        request_id: requestIdHint,
        blueprint_index: inputCtx.blueprint_index ?? null,
        retry_count: inputCtx.retry_count ?? 0,
        retry_instructions: inputCtx.retry_instructions ?? "",
        raw_preview: typeof raw === "string" ? raw.slice(0, 800) : null,
      },
    };
  }

  const parsed = parsedResult.value;
  if (!parsed || parsed.ok !== true || !Array.isArray(parsed.updates)) {
    return {
      json: {
        ok: false,
        status: 422,
        error: "Invalid payload",
        page_type: pageTypeHint,
        request_id: requestIdHint,
        blueprint_index: inputCtx.blueprint_index ?? null,
        retry_count: inputCtx.retry_count ?? 0,
        retry_instructions: inputCtx.retry_instructions ?? "",
        parsed_preview: parsed,
      },
    };
  }

  const cleaned = deepClean(parsed);
  let updates = (Array.isArray(cleaned.updates) ? cleaned.updates : []).map(u => ({
    ...u,
    fields: u?.fields ?? u?.data ?? {},
  }));

  const pageType = cleaned.page_type || pageTypeHint || null;
  const blueprintPostId = parseInt(inputCtx?.blueprint?.post_id || cleaned?.blueprint?.post_id || 0, 10) || 0;
  const safeTargets = new Set(["options", "post_meta", "faq", "service_meta"]);
  const isHomepage = pageType === "homepage";

  const sections = Array.isArray(inputCtx?.blueprint?.sections) ? inputCtx.blueprint.sections : [];

  const allowedFieldMap = (() => {
    const out = new Set();
    for (const section of sections) {
      const sectionId = section?.section_id;
      const allowed = Array.isArray(section?.allowed_field_keys) ? section.allowed_field_keys : [];
      if (!sectionId) continue;
      for (const key of allowed) {
        if (typeof key === "string" && key) out.add(`${sectionId}.${key}`);
      }
    }
    return out;
  })();

  const allowedByTypeMap = (() => {
    const out = {};
    for (const section of sections) {
      const type = section?.section_type;
      const allowed = Array.isArray(section?.allowed_field_keys) ? section.allowed_field_keys : [];
      if (!type) continue;
      if (!out[type]) out[type] = new Set();
      for (const key of allowed) {
        if (typeof key === "string" && key) out[type].add(key);
      }
    }
    return out;
  })();

  const allowedBare = (() => {
    const out = new Set();
    for (const section of sections) {
      const allowed = Array.isArray(section?.allowed_field_keys) ? section.allowed_field_keys : [];
      for (const key of allowed) {
        if (typeof key === "string" && key) out.add(key);
      }
    }
    return out;
  })();

  const sectionIdsByType = {};
  const sectionTypesById = {};
  for (const section of sections) {
    const sid = String(section?.section_id || "");
    const stype = String(section?.section_type || "");
    if (!sid || !stype) continue;
    sectionTypesById[sid] = stype;
    if (!sectionIdsByType[stype]) sectionIdsByType[stype] = [];
    sectionIdsByType[stype].push(sid);
  }

  const sectionAliasTypes = {
    intro: ["content", "content_centered", "content_image", "image_content"],
    about: ["content", "content_centered", "content_image", "image_content"],
    about_snippet: ["content", "content_centered", "content_image", "image_content"],
    services: ["service_grid", "services_offered_here", "service_intro", "service_details"],
    services_overview: ["service_grid", "services_offered_here", "service_intro", "service_details"],
    testimonials: ["trust_bar", "trust_reviews", "reviews", "social_proof"],
    faq: ["faq_accordion"],
    cta: ["cta"],
    hero: ["hero"],
  };

  const exactFieldAliases = {
    "hero.hero_cta_primary": "hero.cta_primary_override",
    "hero.hero_cta_secondary": "hero.cta_secondary_override",
    "cta.cta_primary": "cta.cta_primary_override",
    "cta.cta_secondary": "cta.cta_secondary_override",
    cta_primary: "cta.cta_primary_override",
    cta_secondary: "cta.cta_secondary_override",
  };

  function isAllowedDotKey(key) {
    if (!key.includes(".")) return false;
    const parts = key.split(".", 2);
    const prefix = parts[0];
    const field = parts[1] || "";
    const allowedById = allowedFieldMap.size === 0 || allowedFieldMap.has(key);
    const allowedByType = !allowedByTypeMap[prefix] ? false : allowedByTypeMap[prefix].has(field);
    return allowedById || allowedByType;
  }

  function normalizeDotKey(rawKey) {
    if (typeof rawKey !== "string" || !rawKey.includes(".")) return rawKey;

    let key = exactFieldAliases[rawKey] || rawKey;
    let [rawPrefix, rawField] = key.split(".", 2);
    let prefix = rawPrefix;
    let field = rawField || "";

    if (prefix === "cta") {
      if (field === "section_heading") field = "cta_headline";
      if (field === "section_intro" || field === "section_subheadline") field = "cta_subheadline";
      if (field === "cta_primary") field = "cta_primary_override";
      if (field === "cta_secondary") field = "cta_secondary_override";
    }

    const directKey = `${prefix}.${field}`;
    if (isAllowedDotKey(directKey)) return directKey;

    if (sectionIdsByType[prefix]?.length) {
      for (const sid of sectionIdsByType[prefix]) {
        const k = `${sid}.${field}`;
        if (isAllowedDotKey(k)) return k;
      }
    }

    const aliasTypes = sectionAliasTypes[prefix] || [];
    for (const t of aliasTypes) {
      const ids = sectionIdsByType[t] || [];
      for (const sid of ids) {
        const k = `${sid}.${field}`;
        if (isAllowedDotKey(k)) return k;
      }
    }

    for (const sid of Object.keys(sectionTypesById)) {
      const k = `${sid}.${field}`;
      if (isAllowedDotKey(k)) return k;
    }

    return null;
  }

  function filterFieldsByAllowed(fields) {
    if (!fields || typeof fields !== "object") return fields;
    const next = {};

    for (const rawKey of Object.keys(fields)) {
      const value = fields[rawKey];

      if (rawKey.includes(".")) {
        const normalized = normalizeDotKey(rawKey);
        if (normalized) next[normalized] = value;
        continue;
      }

      const aliasedBare = exactFieldAliases[rawKey] || rawKey;
      if (typeof aliasedBare === "string" && aliasedBare.includes(".")) {
        const normalized = normalizeDotKey(aliasedBare);
        if (normalized) next[normalized] = value;
      } else if (!allowedBare || allowedBare.size === 0 || allowedBare.has(aliasedBare)) {
        next[aliasedBare] = value;
      }
    }

    return next;
  }

  updates = updates
    .map(update => {
      const out = { ...update };
      const targetRaw = typeof out.target === "string" ? out.target.trim() : "";

      if (isHomepage) {
        if (targetRaw === "faq") {
          out.target = "faq";
          return out;
        }
        out.target = "options";
        out.id = "homepage";
        return out;
      }

      if (!safeTargets.has(targetRaw) || targetRaw === "options") {
        out.target = "post_meta";
      } else {
        out.target = targetRaw;
      }

      if (out.target === "post_meta" && (!out.id || out.id === 0) && blueprintPostId) out.id = blueprintPostId;
      if (out.target === "service_meta" && (!out.id || out.id === 0) && blueprintPostId) out.id = blueprintPostId;

      return out;
    })
    .map(out => {
      if (out.target !== "faq") out.fields = filterFieldsByAllowed(out.fields);
      return out;
    })
    .filter(out => {
      if (out.target === "options") return true;
      if (out.target === "faq") return true;
      if (out.target === "service_meta") return !!out.id;
      if (out.target === "post_meta") return !!out.id;
      return false;
    });

  const meta = cleaned.meta && typeof cleaned.meta === "object" ? cleaned.meta : {};
  if (!meta.primary_keyword && primaryHint) meta.primary_keyword = primaryHint;
  if (!meta.secondary_keywords && secondaryHint.length) meta.secondary_keywords = secondaryHint;
  if (!meta.business_name && businessHint) meta.business_name = businessHint;
  if (!meta.city_region && cityHint) meta.city_region = cityHint;
  if (!meta.style_profile_id && styleHint) meta.style_profile_id = styleHint;

  if (pageType === "service") {
    const postId = findPostMetaId(updates);
    const shortDesc = pickShortDesc(updates);
    if (postId && shortDesc) {
      updates.push({
        target: "service_meta",
        id: postId,
        fields: { lf_service_short_desc: shortDesc },
      });
    }
  }

  return {
    json: {
      ok: true,
      request_id: cleaned.request_id || requestIdHint,
      blueprint_index: inputCtx.blueprint_index ?? null,
      retry_count: inputCtx.retry_count ?? 0,
      retry_instructions: inputCtx.retry_instructions ?? "",
      page_type: pageType,
      meta,
      updates,
    },
  };
}

const inputItems = $input.all();
return inputItems.map(item => parseOne(item.json || {}));

// Quality Gate + SEO Enforcement (strict checks, no auto-repair)
const allItems = $input.all();
if (!allItems.length) {
  return [{ json: { ok: true, updates: [], quality_warnings: ["No items for quality gate"] } }];
}

const upstreamFailures = allItems
  .map(i => i?.json || {})
  .filter(j => j && j.ok === false);

const items = allItems.filter(i => i?.json?.ok !== false);

const parseWarnings = upstreamFailures.map(f => {
  const pageType = f.page_type || 'unknown';
  const err = String(f.error || 'unknown_error');
  const detail = String(f.details || '').trim();
  return detail
    ? `Dropped blueprint page_type=${pageType}: ${err} (${detail})`
    : `Dropped blueprint page_type=${pageType}: ${err}`;
});

function normalizeText(value) {
  return String(value || "").toLowerCase().replace(/\s+/g, " ").trim();
}

function wordCount(value) {
  const text = String(value || "").trim();
  if (!text) return 0;
  return text.split(/\s+/).length;
}

function containsKeyword(value, keyword) {
  const hay = normalizeText(value);
  const needle = normalizeText(keyword);
  if (!needle) return false;
  return hay.includes(needle);
}

function extractStrings(updates) {
  const out = [];
  for (const update of updates) {
    const fields = update?.fields || {};
    for (const key of Object.keys(fields)) {
      const value = fields[key];
      if (typeof value === "string") {
        const trimmed = value.trim();
        if (trimmed) out.push({ key, value: trimmed });
      }
    }
  }
  return out;
}

function splitSentences(text) {
  return String(text || "")
    .replace(/\s+/g, " ")
    .split(/[.!?]\s+/)
    .map(s => s.trim())
    .filter(s => s.length >= 16);
}

function detectDuplicateSentences(strings) {
  const seen = new Set();
  for (const { value } of strings) {
    const sentences = splitSentences(value);
    for (const s of sentences) {
      const n = normalizeText(s);
      if (!n) continue;
      if (seen.has(n)) return true;
      seen.add(n);
    }
  }
  return false;
}

function detectDuplicateFields(strings) {
  const seen = new Set();
  for (const { value } of strings) {
    const n = normalizeText(value);
    if (!n) continue;
    if (seen.has(n)) return true;
    seen.add(n);
  }
  return false;
}

function detectCityRepeatInHeadings(strings, cityRegion) {
  if (!cityRegion) return false;
  const city = normalizeText(cityRegion);
  let count = 0;
  for (const { key, value } of strings) {
    if (!/heading|headline|trust_heading|cta_headline/i.test(key)) continue;
    if (normalizeText(value).includes(city)) count += 1;
  }
  return count > 1;
}

function detectInYourArea(strings, pageType) {
  if (pageType === 'service_area') return false;
  for (const { value } of strings) {
    if (/\bin your area\b/i.test(value)) return true;
  }
  return false;
}

function detectGenericPhrases(strings) {
  const patterns = [
    /delivers tailored solutions/i,
    /clear communication, clean execution/i,
    /long-?lasting results/i,
    /fast response and clear pricing/i,
    /upfront pricing before work starts/i,
    /trusted local team/i
  ];
  for (const { value } of strings) {
    for (const re of patterns) {
      if (re.test(value)) return true;
    }
  }
  return false;
}

const warnings = [];
for (const item of items) {
  const json = item.json || {};
  if (!json.ok || !Array.isArray(json.updates)) continue;

  const meta = json.meta || {};
  const primaryKeyword = String(meta.primary_keyword || "").trim();
  const secondaryKeywords = Array.isArray(meta.secondary_keywords) ? meta.secondary_keywords : [];
  const cityRegion = String(meta.city_region || "").trim();
  const pageType = json.page_type || "unknown";

  let totalWords = 0;
  let primaryFound = false;
  let secondaryFound = false;

  const strings = extractStrings(json.updates);
  for (const { value } of strings) {
    totalWords += wordCount(value);
    if (primaryKeyword && containsKeyword(value, primaryKeyword)) primaryFound = true;
    if (!secondaryFound && secondaryKeywords.length) {
      secondaryFound = secondaryKeywords.some(sk => containsKeyword(value, sk));
    }
  }

  if (primaryKeyword && !primaryFound) warnings.push(`Missing primary keyword on ${pageType}.`);
  if (secondaryKeywords.length && !secondaryFound) warnings.push(`Missing secondary keyword on ${pageType}.`);

  if (detectDuplicateFields(strings)) warnings.push(`Duplicate fields detected on ${pageType}.`);
  if (detectDuplicateSentences(strings)) warnings.push(`Repeated sentence detected on ${pageType}.`);
  if (detectCityRepeatInHeadings(strings, cityRegion)) warnings.push(`City repeated in headings on ${pageType}.`);
  if (detectInYourArea(strings, pageType)) warnings.push(`"In your area" detected on ${pageType}.`);
  if (detectGenericPhrases(strings)) warnings.push(`Generic phrasing detected on ${pageType}.`);

  const minTotal = pageType === 'homepage' ? 220 : (pageType === 'post' ? 320 : 140);
  if (totalWords < minTotal) warnings.push(`Low content volume on ${pageType} (${totalWords} words).`);
}

const allWarnings = Array.from(new Set(warnings.concat(parseWarnings)));

// Attach warnings to every item (including ok:false) so Retry Decision can act.
for (const item of allItems) {
  if (!item.json || typeof item.json !== 'object') item.json = {};
  const existing = Array.isArray(item.json.quality_warnings) ? item.json.quality_warnings : [];
  item.json.quality_warnings = Array.from(new Set(existing.concat(allWarnings)));
}

return allItems;
